#include <iostream>
#include <string>

int main() {
  int number = 42;
  double pi = 3.14;
  std::string message = "Hello, C++!";
  std::cout << "Number: " << number << std::endl;
  std::cout << "Pi: " << pi << std::endl;
  std::cout << "Message: " << message << std::endl;
  return 0;
}
// Output:
// Number: 42
// Pi: 3.14
// Message: Hello, C++!

#include <iostream>
#include <iomanip>

int main() {
  double value = 3.14159;
  std::cout << std::fixed << std::setprecision(2);
  std::cout << "Value: " << value << std::endl;
  return 0;
}
// Output:
// Value: 3.14

#include <fstream>
#include <string>

int main() {
  std::ofstream file("output.txt");
  if (file.is_open()) {
    file << "Name: Alice" << std::endl;
    file << "Age: 25" << std::endl;
    file.close();
  }
  return 0;
}
// Output (in output.txt):
// Name: Alice
// Age: 25

#include <fstream>
#include <iostream>
#include <string>

int main() {
  std::ofstream file("data.txt");
  if (file.is_open()) {
    file << "Test data" << std::endl;
    file.close();
  }
  std::ifstream readFile("data.txt");
  std::string line;
  if (readFile.is_open()) {
    std::getline(readFile, line);
    std::cout << "Read from file: " << line << std::endl;
    readFile.close();
  }
  return 0;
}
// Output:
// Read from file: Test data

